// === Casa Container BH - publicador Instagram ===
const IG = "17841449925022438";
const token = "PASTE_SYSTEM_USER_TOKEN_HERE"; // <-- COLE aqui o token que nao expira
const API = "https://graph.facebook.com/v21.0";
const httpRequest = this.helpers.httpRequest.bind(this.helpers);
const RAW = "https://raw.githubusercontent.com/ecs-geo/casacontainer-assets/main/";
const imgs = (slug, n) => Array.from({length:n}, (_,i) => RAW + slug + "/slide-" + (i+1) + ".jpg");

const queue = [
  { images: imgs("03-container-x-alvenaria", 7), caption: "Container ou alvenaria? Vou ser honesto - inclusive sobre quando a alvenaria ganha.\n\nTempo: container fica pronto em poucas semanas; alvenaria leva de 6 a 12 meses.\nObra: quase zero. Chega pronto, sem canteiro bagunçando seu terreno.\nCusto: previsível. Você sabe o valor antes.\nMobilidade: mudou de ideia ou de terreno? O container vai com você.\nSendo justo: alvenaria ainda ganha em áreas muito grandes e projetos bem complexos.\n\nMe conta seu projeto no WhatsApp (31) 99161-2315 que eu te ajudo a decidir.\n\n#casacontainer #container #casacontainerbh #alvenaria #construcaoseca #arquitetura #belohorizonte #casaprefabricada" },
  { images: imgs("04-prazo-entrega", 6), caption: "Em quanto tempo eu mudo pra minha casa container? Bem menos do que você imagina.\n\nUma obra de alvenaria leva de 6 a 12 meses. Um container sai em semanas - porque é fabricado enquanto o seu terreno é preparado, em paralelo. Chega pronto e é instalado no seu terreno em cerca de 1 dia.\n\nQuer começar? Me manda seu projeto no WhatsApp (31) 99161-2315 que eu já te passo o prazo real.\n\n#casacontainer #container #casacontainerbh #casaprefabricada #arquitetura #belohorizonte #construcaoseca #prazodeobra" },
];

if (!token || token.indexOf("PASTE_") === 0) throw new Error("Cole o token do Instagram no no de codigo (token=...)");

const sd = $getWorkflowStaticData("global");
let idx = typeof sd.idx === "number" ? sd.idx : 0;
const post = queue[idx % queue.length];
sd.idx = idx + 1;

const call = async (path, params) => {
  const res = await httpRequest({ method:"POST", url: API + "/" + path, qs: Object.assign({}, params, { access_token: token }) });
  return typeof res === "string" ? JSON.parse(res) : res;
};

const children = [];
for (const url of post.images) {
  const j = await call(IG + "/media", { image_url: url, is_carousel_item: "true" });
  if (j.error) throw new Error("item: " + JSON.stringify(j.error));
  children.push(j.id);
}
const car = await call(IG + "/media", { media_type:"CAROUSEL", children: children.join(","), caption: post.caption });
if (car.error) throw new Error("carousel: " + JSON.stringify(car.error));
const pub = await call(IG + "/media_publish", { creation_id: car.id });
if (pub.error) throw new Error("publish: " + JSON.stringify(pub.error));
return [{ json: { published: true, media_id: pub.id, postIndex: idx } }];
